module top_module(X_in, sx, rst, clk, x_par, fx);input X_in, sx,rst,clk;
	output fx;
	output [11 - 1:0] x_par;
	wire fx; 

	reg [11 - 1:0] x_par;
	reg [3 : 0] countdown;

	assign fx = (countdown >= 11);

	always @(posedge clk or posedge rst) begin
		if(rst) begin
			x_par<= 11'b0;
			countdown<= 4'b0;
		end
		 else if(sx && countdown< 11) begin
			x_par[11-1:0]<={ x_par[11-2:0], X_in};
			countdown <= countdown + 1;
		end

	end

endmodule
